class Solution {
public:
    string baseNeg2(int n) {
        string res;
        while (n) {
            int rem = n % -2;
            n /= -2;
            if (rem < 0) {
                rem += 2;
                n += 1;
            }
            res = to_string(rem) + res;
        }
        return res.empty() ? "0" : res;
    }
};
